#include<bits/stdc++.h>
using namespace std;
map<int,int> mp;
long long ans=1;
int main()
{
	for(int i=2;i<=2024;i++)
	{
		int t=i;
		for(int j=2;j<=t/j;j++)
		{
			if(t%j) continue;
			while(t%j==0)
			{
				t/=j;
				mp[j]++;
			}
		}
		if(t>1) mp[t]++;
	}
	map<int,int> ::iterator it;
	for(it=mp.begin();it!=mp.end();it++)
	{
		ans*=(1+(it->second/61)); 
	}
	cout<<ans;
	return 0;
}
